1233: bool EventListenerManager::HandleEventSingleListener(
1234:     Listener* aListener, nsAtom* aTypeAtom, WidgetEvent* aEvent,
1235:     Event* aDOMEvent, EventTarget* aCurrentTarget, bool aItemInShadowTree) {
1236:   if (!aEvent->mCurrentTarget) {
1237:     aEvent->mCurrentTarget = aCurrentTarget->GetTargetForDOMEvent();
1238:     if (!aEvent->mCurrentTarget) {
1239:       return false;
1240:     }
1241:   }
1242: 
1243:   aEvent->mFlags.mInPassiveListener = aListener->mFlags.mPassive;
1244: 
1245:   nsCOMPtr<nsPIDOMWindowInner> innerWindow =
1246:       WindowFromListener(aListener, aTypeAtom, aItemInShadowTree);
1247:   mozilla::dom::Event* oldWindowEvent = nullptr;
1248:   if (innerWindow) {
1249:     oldWindowEvent = innerWindow->SetEvent(aDOMEvent);
1250:   }
1251: 
1252:   nsresult result = NS_OK;
1253: 
1254:   // strong ref
1255:   EventListenerHolder listenerHolder(aListener->mListener.Clone());
1256: 
1257:   // If this is a script handler and we haven't yet
1258:   // compiled the event handler itself
1259:   if ((aListener->mListenerType == Listener::eJSEventListener) &&
1260:       aListener->mHandlerIsString) {
1261:     result =
1262:         CompileEventHandlerInternal(aListener, aTypeAtom, nullptr, nullptr);
1263:     aListener = nullptr;
1264:   }
1265: 
1266:   if (NS_SUCCEEDED(result)) {
1267:     Maybe<EventCallbackDebuggerNotificationGuard> dbgGuard;
1268:     if (dom::ChromeUtils::IsDevToolsOpened() || profiler_is_active()) {
1269:       dbgGuard.emplace(aCurrentTarget, aDOMEvent);
1270:     }
1271:     nsAutoMicroTask mt;
1272: 
1273:     // Event::currentTarget is set in EventDispatcher.
1274:     if (listenerHolder.HasWebIDLCallback()) {
1275:       ErrorResult rv;
1276:       listenerHolder.GetWebIDLCallback()->HandleEvent(aCurrentTarget,
1277:                                                       *aDOMEvent, rv);
1278:       result = rv.StealNSResult();
1279:     } else {
1280:       // listenerHolder is holding a stack ref here.
1281:       result = MOZ_KnownLive(listenerHolder.GetXPCOMCallback())
1282:                    ->HandleEvent(aDOMEvent);
1283:     }
1284:   }
1285: 
1286:   if (innerWindow) {
1287:     (void)innerWindow->SetEvent(oldWindowEvent);
1288:   }
1289: 
1290:   if (NS_FAILED(result)) {
1291:     aEvent->mFlags.mExceptionWasRaised = true;
1292:   }
1293:   aEvent->mFlags.mInPassiveListener = false;
1294:   return !aEvent->mFlags.mImmediatePropagationStopped;
1295: }
