1343: already_AddRefed<nsPIDOMWindowInner> EventListenerManager::WindowFromListener(
1344:     Listener* aListener, nsAtom* aTypeAtom, bool aItemInShadowTree) {
1345:   nsCOMPtr<nsPIDOMWindowInner> innerWindow;
1346:   if (!aItemInShadowTree) {
1347:     if (aListener->mListener.HasWebIDLCallback()) {
1348:       CallbackObject* callback = aListener->mListener.GetWebIDLCallback();
1349:       nsIGlobalObject* global = nullptr;
1350:       if (callback) {
1351:         global = callback->IncumbentGlobalOrNull();
1352:       }
1353:       if (global) {
1354:         innerWindow = global->GetAsInnerWindow();  // Can be nullptr
1355:       }
1356:     } else if (mTarget) {
1357:       // This ensures `window.event` can be set properly for
1358:       // nsWindowRoot to handle KeyPress event.
1359:       if (aListener && aTypeAtom == nsGkAtoms::onkeypress &&
1360:           mTarget->IsRootWindow()) {
1361:         nsPIWindowRoot* root = mTarget->AsWindowRoot();
1362:         if (nsPIDOMWindowOuter* outerWindow = root->GetWindow()) {
1363:           innerWindow = outerWindow->GetCurrentInnerWindow();
1364:         }
1365:       } else {
1366:         // Can't get the global from
1367:         // listener->mListener.GetXPCOMCallback().
1368:         // In most cases, it would be the same as for
1369:         // the target, so let's do that.
1370:         if (nsIGlobalObject* global = mTarget->GetOwnerGlobal()) {
1371:           innerWindow = global->GetAsInnerWindow();
1372:         }
1373:       }
1374:     }
1375:   }
1376:   return innerWindow.forget();
1377: }
