b apps may be\n9591:       // broken with this strict behavior due to historical issue.\n9592:       // Therefore, we need to keep dispatching keypress event for such keys\n9593:       // even with breaking the standard.\n9594:       // Similarly, the other browsers sets non-zero value of keyCode or\n9595:       // charCode of keypress event to the other.  Therefore, we should\n9596:       // behave so, however, some web apps may be broken.  On such web apps,\n9597:       // we should keep using legacy our behavior.\n9598:       if (!mPresShell-\u003emInitializedWithKeyPressEventDispatchingBlacklist) {\n9599:         mPresShell-\u003emInitializedWithKeyPressEventDispatchingBlacklist = true;\n9600:         nsCOMPtr\u003cnsIPrincipal\u003e principal =\n9601:             GetDocumentPrincipalToCompareWithBlacklist(*mPresShell);\n9602:         if (principal) {\n9603:           mPresShell-\u003emForceDispatchKeyPressEventsForNonPrintableKeys =\n9604:               principal-\u003eIsURIInPrefList(\n9605:                   \"dom.keyboardevent.keypress.hack.dispatch_non_printable_\"\n9606:                   \"keys\") ||\n9607:               principal-\u003eIsURIInPrefList(\n9608:                   \"dom.keyboardevent.keypress.hack.\"\n9609:                   \"dispatch_non_printable_keys.addl\");\n9610: \n9611:           mPresShell-\u003emForceUseLegacyKeyCodeAndCharCodeValues |=\n9612:               principal-\u003eIsURIInPrefList(\n9613:                   \"dom.keyboardevent.keypress.hack.\"\n9614:                   \"use_legacy_keycode_and_charcode\") ||\n9615:               principal-\u003eIsURIInPrefList(\n9616:                   \"dom.keyboardevent.keypress.hack.\"\n9617:                   \"use_legacy_keycode_and_charcode.addl\");\n9618:         }\n9619:       }\n9620:       if (mPresShell-\u003emForceDispatchKeyPressEventsForNonPrintableKeys) {\n9621:         aEvent-\u003emFlags.mOnlySystemGroupDispatchInContent = false;\n9622:       }\n9623:       if (mPresShell-\u003emForceUseLegacyKeyCodeAndCharCodeValues) {\n9624:         aEvent-\u003eAsKeyboardEvent()-\u003emUseLegacyKeyCodeAndCharCodeValues = true;\n9625:       }\n9626:     }\n9627: \n9628:     if (aEvent-\u003emClass == eCompositionEventClass) {\n9629:       RefPtr\u003cnsPresContext\u003e presContext = GetPresContext();\n9630:       RefPtr\u003cBrowserParent\u003e browserParent =\n9631:           IMEStateManager::GetActiveBrowserParent();\n9632:       IMEStateManager::DispatchCompositionEvent(\n9633:           eventTarget, presContext, browserParent, aEvent-\u003eAsCompositionEvent(),\n9634:           aEventStatus, eventCBPtr);\n9635:     } else {\n9636:       if (aEvent-\u003eIsMouseEventClassOrHasClickRelatedPointerEvent()) {\n9637:         PointerEventHandler::RecordMouseButtons(*aEvent-\u003eAsMouseEvent());\n9638: #ifdef DEBUG\n9639:         if (eventTarget-\u003eIsContent() \u0026\u0026 !eventTarget-\u003eIsElement()) {\n9640:           NS_WARNING(nsPrintfCString(\n9641:                          \"%s (IsReal()=%s) target is not an elemnet content \"\n9642:                          \"node, %s\\n\",\n9643:                          ToChar(aEvent-\u003emMessage),\n9644:                          aEvent-\u003eAsMouseEvent()-\u003eIsReal() ? \"true\" : \"false\",\n9645:                          ToString(*eventTarget).c_str())\n9646:                          .get());\n9647:           MOZ_CRASH(\"MouseEvent target must be an element\");\n9648:         }\n9649: #endif  // #ifdef DEBUG\n9650:       }\n9651: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/firefox--871325b8@01dcdcebaca08ed5c32f8d50532752a063dc5ade/-/blob/layout/base/PresShell.cpp%3FL9554-9650"}", "annotations": null, "meta": null}], "structuredContent": {"content": "9554: 
9555: nsresult PresShell::EventHandler::DispatchEventToDOM(
9556:     WidgetEvent* aEvent, nsEventStatus* aEventStatus,
9557:     nsPresShellEventCB* aEventCB) {
9558:   nsresult rv = NS_OK;
9559:   nsCOMPtr<nsINode> eventTarget = mPresShell->mCurrentEventTarget.mContent;
9560:   nsPresShellEventCB* eventCBPtr = aEventCB;
9561:   if (!eventTarget) {
9562:     nsCOMPtr<nsIContent> targetContent;
9563:     if (mPresShell->mCurrentEventTarget.mFrame) {
9564:       targetContent =
9565:           mPresShell->mCurrentEventTarget.mFrame->GetContentForEvent(aEvent);
9566:       if (targetContent && !targetContent->IsElement() &&
9567:           IsForbiddenDispatchingToNonElementContent(aEvent->mMessage)) {
9568:         targetContent =
9569:             targetContent->GetInclusiveFlattenedTreeAncestorElement();
9570:       }
9571:     }
9572:     if (targetContent) {
9573:       eventTarget = targetContent;
9574:     } else if (GetDocument()) {
9575:       eventTarget = GetDocument();
9576:       // If we don't have any content, the callback wouldn't probably
9577:       // do nothing.
9578:       eventCBPtr = nullptr;
9579:     }
9580:   }
9581:   if (eventTarget) {
9582:     if (eventTarget->OwnerDoc()->ShouldResistFingerprinting(
9583:             RFPTarget::WidgetEvents) &&
9584:         aEvent->IsBlockedForFingerprintingResistance()) {
9585:       aEvent->mFlags.mOnlySystemGroupDispatchInContent = true;
9586:     } else if (aEvent->mMessage == eKeyPress) {
9587:       // If eKeyPress event is marked as not dispatched in the default event
9588:       // group in web content, it's caused by non-printable key or key
9589:       // combination.  In this case, UI Events declares that browsers
9590:       // shouldn't dispatch keypress event.  However, some web apps may be
9591:       // broken with this strict behavior due to historical issue.
9592:       // Therefore, we need to keep dispatching keypress event for such keys
9593:       // even with breaking the standard.
9594:       // Similarly, the other browsers sets non-zero value of keyCode or
9595:       // charCode of keypress event to the other.  Therefore, we should
9596:       // behave so, however, some web apps may be broken.  On such web apps,
9597:       // we should keep using legacy our behavior.
9598:       if (!mPresShell->mInitializedWithKeyPressEventDispatchingBlacklist) {
9599:         mPresShell->mInitializedWithKeyPressEventDispatchingBlacklist = true;
9600:         nsCOMPtr<nsIPrincipal> principal =
9601:             GetDocumentPrincipalToCompareWithBlacklist(*mPresShell);
9602:         if (principal) {
9603:           mPresShell->mForceDispatchKeyPressEventsForNonPrintableKeys =
9604:               principal->IsURIInPrefList(
9605:                   "dom.keyboardevent.keypress.hack.dispatch_non_printable_"
9606:                   "keys") ||
9607:               principal->IsURIInPrefList(
9608:                   "dom.keyboardevent.keypress.hack."
9609:                   "dispatch_non_printable_keys.addl");
9610: 
9611:           mPresShell->mForceUseLegacyKeyCodeAndCharCodeValues |=
9612:               principal->IsURIInPrefList(
9613:                   "dom.keyboardevent.keypress.hack."
9614:                   "use_legacy_keycode_and_charcode") ||
9615:               principal->IsURIInPrefList(
9616:                   "dom.keyboardevent.keypress.hack."
9617:                   "use_legacy_keycode_and_charcode.addl");
9618:         }
9619:       }
9620:       if (mPresShell->mForceDispatchKeyPressEventsForNonPrintableKeys) {
9621:         aEvent->mFlags.mOnlySystemGroupDispatchInContent = false;
9622:       }
9623:       if (mPresShell->mForceUseLegacyKeyCodeAndCharCodeValues) {
9624:         aEvent->AsKeyboardEvent()->mUseLegacyKeyCodeAndCharCodeValues = true;
9625:       }
9626:     }
9627: 
9628:     if (aEvent->mClass == eCompositionEventClass) {
9629:       RefPtr<nsPresContext> presContext = GetPresContext();
9630:       RefPtr<BrowserParent> browserParent =
9631:           IMEStateManager::GetActiveBrowserParent();
9632:       IMEStateManager::DispatchCompositionEvent(
9633:           eventTarget, presContext, browserParent, aEvent->AsCompositionEvent(),
9634:           aEventStatus, eventCBPtr);
