tFrame();\n461:       if (!frame \u0026\u0026 (aVisitor.mEvent-\u003emMessage == eMouseUp ||\n462:                      aVisitor.mEvent-\u003emMessage == eTouchEnd)) {\n463:         // Redirect BUTTON_UP and TOUCH_END events to the root frame to ensure\n464:         // that capturing is released.\n465:         frame = mPresShell-\u003eGetRootFrame();\n466:       }\n467:       if (frame) {\n468:         frame-\u003eHandleEvent(aVisitor.mPresContext, aVisitor.mEvent-\u003eAsGUIEvent(),\n469:                            \u0026aVisitor.mEventStatus);\n470:       }\n471:     }\n472:   }\n473: \n474:   RefPtr\u003cPresShell\u003e mPresShell;\n475: };\n476: \n477: class nsBeforeFirstPaintDispatcher : public Runnable {\n478:  public:\n479:   explicit nsBeforeFirstPaintDispatcher(Document* aDocument)\n480:       : mozilla::Runnable(\"nsBeforeFirstPaintDispatcher\"),\n481: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/firefox--871325b8@01dcdcebaca08ed5c32f8d50532752a063dc5ade/-/blob/layout/base/PresShell.cpp%3FL430-480"}", "annotations": null, "meta": null}], "structuredContent": {"content": "430: 
431: class MOZ_STACK_CLASS nsPresShellEventCB : public EventDispatchingCallback {
432:  public:
433:   explicit nsPresShellEventCB(PresShell* aPresShell) : mPresShell(aPresShell) {}
434: 
435:   MOZ_CAN_RUN_SCRIPT
436:   virtual void HandleEvent(EventChainPostVisitor& aVisitor) override {
437:     if (aVisitor.mPresContext && aVisitor.mEvent->mClass != eBasicEventClass) {
438:       if (aVisitor.mEvent->mMessage == eMouseDown ||
439:           aVisitor.mEvent->mMessage == eMouseUp) {
440:         // Mouse-up and mouse-down events call nsIFrame::HandlePress/Release
441:         // which call GetContentOffsetsFromPoint which requires up-to-date
442:         // layout. Bring layout up-to-date now so that GetCurrentEventFrame()
443:         // below will return a real frame and we don't have to worry about
444:         // destroying it by flushing later.
445:         MOZ_KnownLive(mPresShell)->FlushPendingNotifications(FlushType::Layout);
446:       } else if (aVisitor.mEvent->mMessage == eWheel &&
447:                  aVisitor.mEventStatus != nsEventStatus_eConsumeNoDefault) {
448:         nsIFrame* frame = mPresShell->GetCurrentEventFrame();
449:         if (frame) {
450:           // chrome (including addons) should be able to know if content
451:           // handles both D3E "wheel" event and legacy mouse scroll events.
452:           // We should dispatch legacy mouse events before dispatching the
453:           // "wheel" event into system group.
454:           RefPtr<EventStateManager> esm =
455:               aVisitor.mPresContext->EventStateManager();
456:           esm->DispatchLegacyMouseScrollEvents(
457:               frame, aVisitor.mEvent->AsWheelEvent(), &aVisitor.mEventStatus);
458:         }
459:       }
460:       nsIFrame* frame = mPresShell->GetCurrentEventFrame();
461:       if (!frame && (aVisitor.mEvent->mMessage == eMouseUp ||
462:                      aVisitor.mEvent->mMessage == eTouchEnd)) {
463:         // Redirect BUTTON_UP and TOUCH_END events to the root frame to ensure
464:         // that capturing is released.
465:         frame = mPresShell->GetRootFrame();
466:       }
467:       if (frame) {
468:         frame->HandleEvent(aVisitor.mPresContext, aVisitor.mEvent->AsGUIEvent(),
469:                            &aVisitor.mEventStatus);
470:       }
471:     }
472:   }
473: 
474:   RefPtr<PresShell> mPresShell;
475: };
